<!DOCTYPE html>
<html>
<head>
  <title>Falling Sand</title>
  <style>
    body {
      background-color: #1e1e1e;
      display: flex;
      justify-content: center;
      align-items: center;
      height: 100vh;
      margin: 0;
      font-family: sans-serif;
    }

    #container {
      width: 800px;
      height: 600px;
      position: relative;
    }

    #canvas {
      background-color: #282c34;
      border: none;
      display: block;
    }

    .button {
      background-color: #3e4451;
      color: white;
      padding: 10px 20px;
      border: none;
      cursor: pointer;
      margin: 5px;
      font-size: 16px;
    }

    .button:hover {
      background-color: #434c5e;
    }
  </style>
</head>
<body>
  <div id="container">
    <canvas id="canvas"></canvas>

    <div>
      <button class="button" id="mat-sand">Sand</button>
      <button class="button" id="mat-water">Water</button>
      <button class="button" id="mat-wall">Wall</button>
      <button class="button" id="mat-acid">Acid</button>
      <button class="button" id="mat-empty">Empty (Eraser)</button>
      <button class="button" id="clear">Clear</button>
    </div>
  </div>

  <script>
    const w = 80;
    const h = 60;
    const cellSize = 20;
    const canvasWidth = w * cellSize;
    const canvasHeight = h * cellSize;

    const canvas = document.getElementById('canvas');
    canvas.width = canvasWidth;
    canvas.height = canvasHeight;
    const ctx = canvas.getContext('2d');

    let grid = [];
    for (let y = 0; y < h; y++) {
      grid[y] = [];
      for (let x = 0; x < w; x++) {
        grid[y][x] = 'empty';
      }
    }

    let mouseX = 0;
    let mouseY = 0;
    let isDragging = false;

    const materials = ['empty', 'sand', 'water', 'wall', 'acid'];

    function draw() {
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          const material = grid[y][x];
          const colorMap = {
            'empty': '#282c34',
            'sand': '#a89167',
            'water': '#456d7f',
            'wall': '#5e81ac',
            'acid': '#ff6b6b'
          };

          ctx.fillStyle = colorMap[material];
          ctx.fillRect(x * cellSize, y * cellSize, cellSize, cellSize);
        }
      }
    }


    canvas.addEventListener('mousedown', (e) => {
      const rect = canvas.getBoundingClientRect();
      mouseX = e.clientX - rect.left;
      mouseY = e.clientY - rect.top;
      isDragging = true;
    });

    canvas.addEventListener('mouseup', () => {
      isDragging = false;
    });

    canvas.addEventListener('mousemove', (e) => {
      if (!isDragging) return;
      const rect = canvas.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      const gridX = Math.floor(x / cellSize);
      const gridY = Math.floor(y / cellSize);

      if (gridX >= 0 && gridX < w && gridY >= 0 && gridY < h) {
        set(gridX, gridY, materials[0]); // Set to empty for dragging
      }
    });


    function set(x, y, material) {
      if (x < 0 || x >= w || y < 0 || y >= h) return;

      const originalMaterial = grid[y][x];
      if (originalMaterial !== material) {
        grid[y][x] = material;
      }
    }


    function tick(n) {
      for (let i = 0; i < n; i++) {
        simulateStep();
      }
    }

    function simulateStep() {
      const newGrid = grid.map(row => [...row]); // Deep copy

      for (let y = h - 1; y >= 0; y--) {
        for (let x = 0; x < w; x++) {
          const material = newGrid[y][x];

          if (material === 'sand') {
            // Try to move down
            if (y + 1 < h && newGrid[y + 1][x] === 'empty') {
              newGrid[y + 1][x] = material;
              newGrid[y][x] = 'empty';
            } else {
              // Try to slide diagonally down-left
              if (y + 1 < h && x - 1 >= 0 && newGrid[y + 1][x - 1] === 'empty') {
                newGrid[y + 1][x - 1] = material;
                newGrid[y][x] = 'empty';
              } else if (y + 1 < h && x + 1 < w && newGrid[y + 1][x + 1] === 'empty') {
                newGrid[y + 1][x + 1] = material;
                newGrid[y][x] = 'empty';
              }
            }
          } else if (material === 'water') {
            // Spread horizontally
            const directions = ['left', 'right'];
            const randomDirection = directions[Math.floor(Math.random() * 2)];

            if (randomDirection === 'left' && x > 0 && newGrid[y][x - 1] === 'empty') {
              newGrid[y][x - 1] = material;
              newGrid[y][x] = 'empty';
            } else if (randomDirection === 'right' && x < w - 1 && newGrid[y][x + 1] === 'empty') {
              newGrid[y][x + 1] = material;
              newGrid[y][x] = 'empty';
            }
          } else if (material === 'acid') {
            // Move like water and dissolve
            const directions = ['left', 'right'];
            const randomDirection = directions[Math.floor(Math.random() * 2)];

            if (randomDirection === 'left' && x > 0 && newGrid[y][x - 1] === 'sand' || newGrid[y][x-1] === 'wall') {
              newGrid[y][x - 1] = 'empty';
              newGrid[y][x] = 'empty';
            } else if (randomDirection === 'right' && x < w - 1 && newGrid[y][x + 1] === 'sand' || newGrid[y][x+1] === 'wall') {
              newGrid[y][x + 1] = 'empty';
              newGrid[y][x] = 'empty';
            }
          }
        }
      }

      // Update the grid with the changes
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          grid[y][x] = newGrid[y][x];
        }
      }

      draw();
    }


    function clear() {
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          grid[y][x] = 'empty';
        }
      }
      draw();
    }

    window.sim = {
      w,
      h,
      tick: tick,
      get: (x, y) => grid[y][x],
      set: (x, y, material) => set(x, y, material),
      clear: clear
    };

    window.addEventListener('resize', () => {
      canvasWidth = w * cellSize;
      canvasHeight = h * cellSize;
      canvas.width = canvasWidth;
      canvas.height = canvasHeight;
    });

    // Initial draw
    draw();
  </script>
</body>
</html>
